-- Prompting Grundlagen - "Was ist KI?" module (aa110000-0000-0000-0000-000000000001)

('aa110000-0000-0000-0000-000000000001', 'KI-Glossar: Begriffe die du kennen musst', 'Von API bis Zero-Shot: Die wichtigsten KI-Begriffe erklärt.', 'worksheet', 4, 480, '{"content_html": "<h2>KI-Glossar für Business</h2><dl><dt><b>LLM (Large Language Model)</b></dt><dd>KI-Modell, das auf riesigen Textmengen trainiert wurde (z.B. GPT, Claude, Gemini)</dd><dt><b>Prompt</b></dt><dd>Die Anweisung/Frage, die du an die KI gibst</dd><dt><b>Token</b></dt><dd>Kleinste Texteinheit (~4 Zeichen). Bestimmt Kosten und Kontextlänge</dd><dt><b>Kontext-Fenster</b></dt><dd>Wie viel Text die KI gleichzeitig verarbeiten kann (z.B. 128K Token)</dd><dt><b>Halluzination</b></dt><dd>Wenn die KI überzeugend klingende, aber falsche Infos generiert</dd><dt><b>Fine-Tuning</b></dt><dd>Nachtraining eines Modells auf eigene Daten</dd><dt><b>RAG (Retrieval-Augmented Generation)</b></dt><dd>KI sucht erst in deinen Dokumenten, dann antwortet sie</dd><dt><b>Zero-Shot</b></dt><dd>Prompt ohne Beispiele</dd><dt><b>Few-Shot</b></dt><dd>Prompt mit 2-3 Beispielen für bessere Ergebnisse</dd><dt><b>Temperature</b></dt><dd>Kreativitäts-Regler (0 = exakt, 1 = kreativ)</dd><dt><b>System Prompt</b></dt><dd>Versteckte Anweisung, die das Verhalten der KI grundlegend steuert</dd><dt><b>API</b></dt><dd>Schnittstelle um KI-Modelle programmatisch anzusprechen</dd></dl>"}');

-- "Dein erster Prompt" module (aa110000-0000-0000-0000-000000000002)

('aa110000-0000-0000-0000-000000000002', 'Übung: Prompt-Verbesserung', 'Verbessere 5 schlechte Prompts zu professionellen Anweisungen.', 'task', 4, 900, '{"content_html": "<h2>Übung: Prompts verbessern</h2><p>Verbessere diese 5 Prompts:</p><h3>1. Original:</h3><pre>Schreib eine E-Mail</pre><p>Deine verbesserte Version: ___</p><h3>2. Original:</h3><pre>Mach mir einen Social Media Plan</pre><p>Deine verbesserte Version: ___</p><h3>3. Original:</h3><pre>Analysiere meinen Kunden</pre><p>Deine verbesserte Version: ___</p><h3>4. Original:</h3><pre>Erstelle ein Angebot</pre><p>Deine verbesserte Version: ___</p><h3>5. Original:</h3><pre>Hilf mir beim Verkaufen</pre><p>Deine verbesserte Version: ___</p><p><b>Tipp:</b> Nutze RACE oder CRISP für jede Verbesserung!</p>"}');

